import SwiftUI

enum WindowSheet: Identifiable {
    case foodAnalysis(FoodAnalysis)

    var id: String {
        switch self {
        case .foodAnalysis: return "foodAnalysis"
        }
    }
}

extension View {
    @ViewBuilder
    func overlayModal<OverlayContent: View, SheetContent: View>(
        activeSheet: Binding<WindowSheet?>,
        @ViewBuilder content: () -> OverlayContent,
        @ViewBuilder sheetContent: @escaping (WindowSheet) -> SheetContent
    ) -> some View {
        modifier(AlertPresentationWindowContext(
            activeSheet: activeSheet,
            modalContent: content,
            sheetContent: sheetContent
        ))
    }
}

private struct AlertPresentationWindowContext<OverlayContent: View, SheetContent: View>: ViewModifier {

    @Binding var activeSheet: WindowSheet?

    @ViewBuilder var modalContent: OverlayContent
    var sheetContent: (WindowSheet) -> SheetContent

    @State private var alertWindow: UIWindow?
    @State private var mainKeyWindow: UIWindow?

    func body(content: Content) -> some View {
        content
            .onAppear {
                guard alertWindow == nil else { return }
                guard let window = UIApplication.mainKeyWindow, let windowScene = window.windowScene else { return }
                self.mainKeyWindow = window
                let alertWindow = PassThroughWindow(windowScene: windowScene)
                let alertViewController = UIHostingController(
                    rootView: modalContent
                        .sheet(
                            item: $activeSheet,
                            onDismiss: {
                                mainKeyWindow?.makeKeyAndVisible()
                            },
                            content: sheetContent
                        )
                )
                alertViewController.view.backgroundColor = .clear
                alertWindow.rootViewController = alertViewController
                alertWindow.isHidden = false
                alertWindow.windowLevel = .alert
                self.alertWindow = alertWindow
            }
    }
}

