//
//  UniversalSheet.swift
//  Radiacode
//
//  Created by Matvey Kozin on 01.11.2024.
//

import SwiftUI

// Универсальный модификатор для Item
private struct UniversalSheetForItem<Item: Identifiable, SheetContent: View>: ViewModifier {

    @Binding var item: Item?
    var onDismiss: (() -> Void)?
    var sheetContent: (Item) -> SheetContent

    func body(content: Content) -> some View {
        content
            .if(UIDevice.isIPad) { view in
                view.fullScreenCover(item: $item, onDismiss: onDismiss, content: sheetContent)
            } else: { view in
                view.sheet(item: $item, onDismiss: onDismiss) { sheet in
                    sheetContent(sheet)
                        .presentationDetents([.large])
                }
            }
    }
}

// Универсальный модификатор для Bool
private struct UniversalSheetForBool<SheetContent: View>: ViewModifier {
    @Binding var isPresented: Bool
    var onDismiss: (() -> Void)?
    var sheetContent: () -> SheetContent

    func body(content: Content) -> some View {
        content
            .if(UIDevice.isIPad) { view in
                view.fullScreenCover(isPresented: $isPresented, onDismiss: onDismiss, content: sheetContent)
            } else: { view in
                view.sheet(isPresented: $isPresented, onDismiss: onDismiss) {
                    sheetContent()
                        .presentationDetents([.large])
                }
            }
    }
}

extension View {
    func universalSheet<Item: Identifiable, Content: View>(item: Binding<Item?>, onDismiss: (() -> Void)? = nil, @ViewBuilder content: @escaping (Item) -> Content) -> some View {
        self.modifier(UniversalSheetForItem(item: item, onDismiss: onDismiss, sheetContent: content))
    }

    func universalSheet<Content: View>(isPresented: Binding<Bool>, onDismiss: (() -> Void)? = nil, @ViewBuilder content: @escaping () -> Content) -> some View {
        self.modifier(UniversalSheetForBool(isPresented: isPresented, onDismiss: onDismiss, sheetContent: content))
    }
}

